// showNotes reports whether the "What's new" block should render at
// first paint — only when a check has surfaced a newer/staged release
// with notes to show.
func showNotes(d SystemPageData) bool {
	return d.ReleaseNotes != "" && (d.HasStaged || d.Phase == "staged" || d.Phase == "downloading" || d.Phase == "no-asset")
}

// showNoAsset reports whether the "no build for your platform" banner
// should render at first paint.
func showNoAsset(d SystemPageData) bool { return d.Phase == "no-asset" }

// notesHeadline is the "vCurrent → vLatest · Released <date>" line above
// the release notes. Falls back gracefully when a field is missing.
func notesHeadline(d SystemPageData) string {
	cur := orDash(d.CurrentVersion)
	latest := d.LatestVersion
	if latest == "" {
		latest = d.StagedVersion
	}
	head := cur + " → " + orDash(latest)
	if d := fmtReleaseDate(d.PublishedAt); d != "" {
		head += " · Released " + d
	}
	return head
}

// fmtReleaseDate turns an RFC3339 timestamp into a plain YYYY-MM-DD.
// Returns "" when empty or unparseable so the caller can omit it.
func fmtReleaseDate(s string) string {
	if s == "" {
		return ""
	}
	if t, err := time.Parse(time.RFC3339, s); err == nil {
		return t.Format("2006-01-02")
	}
	// Already a date-ish string or unknown format — show the leading 10
	// chars (YYYY-MM-DD) if they look like a date, else nothing.
	if len(s) >= 10 {
		return s[:10]
	}
	return ""
}

// dbLine joins the db type + status into one cell, e.g. "sqlite · connected".
func dbLine(d SystemPageData) string {
	t := orDash(d.DBType)
	if d.DBStatus == "" {
		return t
	}
	return t + " · " + d.DBStatus
}

