// updateBadgeText returns the badge label for the current phase, or ""
// to hide it (idle / checking / before any check).
func updateBadgeText(d SystemPageData) string {
	switch d.Phase {
	case "up-to-date":
		return "Latest"
	case "staged", "downloading", "no-asset":
		if d.LatestVersion != "" {
			return "Update available → " + d.LatestVersion
		}
		return "Update available"
	}
	if d.HasStaged {
		if d.StagedVersion != "" {
			return "Update available → " + d.StagedVersion
		}
		return "Update available"
	}
	return ""
}

// updateBadgeClass picks the badge color: green when up to date, amber
// when an update is available.
func updateBadgeClass(d SystemPageData) string {
	base := "rounded-full px-2 py-0.5 text-xs font-medium "
	if d.Phase == "up-to-date" {
		return base + "bg-pos-100 text-pos-400"
	}
	return base + "bg-amber-50 text-amber-700 dark:bg-amber-900/40 dark:text-amber-300"
}

